1	// Session-transcript parsing for conversation-surface rules (Stop hook only —
2	// CI has no transcript, so rules must return [] when ctx.conversation() is null).
3	// A Claude Code transcript is JSONL; the shapes this reads were verified against
4	// a real session file, not inferred: an owner turn is `type: "user"` with plain
5	// string message content (tool results arrive as content arrays, injected/meta
6	// turns carry isMeta, subagent traffic carries isSidechain, and synthetic turns
7	// — hook output, reminders, webhook activity — are tag-wrapped, starting with "<").
8	
9	export function parseEntries(text) {
10	  const entries = [];
11	  for (const line of (text || '').split('\n')) {
12	    if (!line.trim()) continue;
13	    try { entries.push(JSON.parse(line)); } catch { /* partial trailing write — skip the line */ }
14	  }
15	  return entries;
16	}
17	
18	function humanText(entry) {
19	  if (entry.type !== 'user' || entry.isMeta || entry.isSidechain) return null;
20	  const content = entry.message?.content;
21	  const text = typeof content === 'string'
22	    ? content
23	    : Array.isArray(content) && content.length && content.every((c) => c?.type === 'text')
24	      ? content.map((c) => c.text).join('\n')
25	      : null;
26	  if (!text || text.trimStart().startsWith('<')) return null;
27	  return text;
