1	import { spawnSync } from 'node:child_process';
2	import { readFileSync, existsSync, statSync } from 'node:fs';
3	import { join, resolve, sep } from 'node:path';
4	import { parseEntries } from './session-transcript.mjs';
5	import { SHARED_SUBDIR, packEntryId } from '../../pack_loader/pack-registry.mjs';
6	
7	function sh(root, cmd, args, { allowFail = false, input = undefined } = {}) {
8	  const r = spawnSync(cmd, args, { cwd: root, encoding: 'utf8', maxBuffer: 64 * 1024 * 1024, input });
9	  if (r.status !== 0 && !allowFail) {
10	    throw new Error(`${cmd} ${args.join(' ')} failed (${r.status}): ${r.stderr}`);
11	  }
12	  return r.status === 0 ? r.stdout : null;
13	}
14	
15	const git = (root, ...args) => sh(root, 'git', args);
16	const gitTry = (root, ...args) => sh(root, 'git', args, { allowFail: true });
17	
18	function resolveBaseRef(root) {
19	  for (const ref of ['origin/main', 'origin/master', 'main', 'master']) {
20	    if (gitTry(root, 'rev-parse', '--verify', '--quiet', `${ref}^{commit}`) !== null) return ref;
21	  }
22	  return null;
23	}
24	
25	function lines(out) {
26	  return (out || '').split('\n').filter(Boolean);
27	}
28	
29	// Files git marks vendored or generated (linguist-vendored / linguist-generated in
30	// .gitattributes) — third-party or machine-written content, not the project's own
31	// code. `buildContext` drops these from the default `ctx.files`, so every check that
32	// reasons about "the project's code" skips them for free: a suppression marker inside
33	// a recorded fixture, a placement "violation" in a generated artifact, and a dangling
34	// link in a vendored doc are none of them the project's decision. `git check-attr`
35	// honors .gitattributes patterns/precedence natively (paths on stdin so a large repo
36	// can't overflow the arg list). The unfiltered set stays on `ctx.allFiles` for the one
37	// check that reasons *about* generated files (generated-merge-driver).
38	function vendoredSet(root, files) {
39	  const set = new Set();
40	  if (!files.length) return set;
41	  const out = sh(root, 'git', ['check-attr', '--stdin', 'linguist-vendored', 'linguist-generated'],
42	    { allowFail: true, input: files.join('\n') + '\n' });
43	  for (const line of (out || '').split('\n')) {
44	    const m = /^(.*): (?:linguist-vendored|linguist-generated): (.*)$/.exec(line);
45	    if (m && m[2] === 'set') set.add(m[1]);
46	  }
47	  return set;
48	}
49	
50	// The complete set of top-level settings .claudinite-checks.json may carry. A key
51	// outside this set is a typo or a stale name — a settings error as real as invalid
52	// JSON, caught at load so it can't silently change nothing. `packConfig` is the
53	// legacy home of per-pack parameters — still honored while the fleet migrates to
54	// pack-entry `config` (the baselining folds it in), no longer documented. The
55	// `pack-entry-config` baseline migration (migrations/active_migrations/) tracks
56	// the fleet's convergence; when it retires, drop the key here (and the overlay
57	// below) so a straggler gets the unknown-setting error.
58	// `claudinite` is the vendored-mount stamp — { updated: "<ISO datetime>", ref: "<sha>" },
59	// written by the nightly update pass, selecting which migration notes still apply
60	// (vendoring/DESIGN.md owns the model); the checks engine itself only tolerates it.
61	export const CONFIG_KEYS = ['packs', 'rules', 'accept', 'sharedConstants', 'packConfig', 'maintenance', 'claudinite'];
62	
63	// The properties a `packs` entry object may carry: the pack's parameters
64	// (`config`), its adoption-interview answers (`answers` — the owner's verbatim
65	// responses to the questions the pack declares on its pack.mjs, keyed by
66	// question id; read by the adoption skill's interview machinery), and the rule overrides / acceptances that
67	// exist BECAUSE this pack is declared (`rules`, `accept` — they may name any
68	// rule; the entry is their provenance). `via` is written by
69	// resolveDeclaredPacks on materialized dependencies (engine/pack_loader/pack-registry.mjs).
70	export const PACK_ENTRY_KEYS = ['id', 'config', 'answers', 'rules', 'accept', 'via'];
71	
72	// Load and validate the project's settings. Validity is checked at load — the
73	// moment Claudinite reads the file — and every problem is collected into `errors`
74	// (each `{ what, fix }`), the runner's single settings-validity gate. A wrong
75	// property name, malformed JSON, and a wrong pack name are all equally settings
76	// errors; unknown *pack* names need the registry, so the runner adds those (it
77	// holds the known-pack list). On unparsable/misshaped JSON the usable fields fall
78	// back to empty so the rest of a sweep still runs, with the error reported.
79	//
80	// The returned shape is NORMALIZED: `packs` is plain BARE ids (a local pack's
81	// namespaced `local_packs/<id>` token resolves through packEntryId, so every
82	// downstream lookup — packEntries, the packConfig view — keys by the pack's
83	// own id whichever form the file used), `rules` and `accept` are the top-level
84	// and per-entry settings merged (an entry-sourced acceptance carries
85	// `pack: <id>` as provenance; conflicting severity overrides are a settings
86	// error), and `packConfig` is the per-pack parameter view — each entry's
87	// `config`, overlaid on the legacy top-level key. Checks and env machinery
88	// read this one shape regardless of which form the file used.
89	export function loadConfig(root) {
90	  const path = join(root, '.claudinite-checks.json');
91	  const empty = { packs: [], packEntries: [], rules: {}, accept: [], sharedConstants: [], packConfig: {}, errors: [] };
92	  if (!existsSync(path)) return empty;
93	
94	  let raw;
95	  try {
96	    raw = JSON.parse(readFileSync(path, 'utf8'));
97	  } catch (e) {
98	    return { ...empty, errors: [{ what: `.claudinite-checks.json is not valid JSON: ${e.message}`, fix: 'fix the JSON syntax' }] };
99	  }
100	  if (raw === null || typeof raw !== 'object' || Array.isArray(raw)) {
101	    return { ...empty, errors: [{ what: '.claudinite-checks.json must be a JSON object', fix: 'wrap the settings in an object: { "packs": [ ... ] }' }] };
102	  }
103	
104	  const errors = [];
105	  for (const key of Object.keys(raw)) {
106	    if (!CONFIG_KEYS.includes(key)) {
107	      errors.push({ what: `unknown setting "${key}"`, fix: `remove it or fix the name — valid settings: ${CONFIG_KEYS.join(', ')}` });
108	    }
109	  }
110	
111	  // --- packs: each entry a pack id or { id, config?, rules?, accept?, via? } ---
112	  const packs = [];
113	  const packEntries = [];
114	  for (const entry of Array.isArray(raw.packs) ? raw.packs : []) {
115	    if (typeof entry === 'string') {
116	      packs.push(packEntryId(entry));
117	      packEntries.push({ id: packEntryId(entry) });
118	      continue;
119	    }
120	    if (entry === null || typeof entry !== 'object' || Array.isArray(entry)) {
121	      errors.push({ what: `packs entry ${JSON.stringify(entry)} is neither a pack id nor an entry object`, fix: 'declare a pack as "name" or { "id": "name", ... }' });
122	      continue;
123	    }
124	    if (typeof entry.id !== 'string') {
125	      errors.push({ what: `packs entry ${JSON.stringify(entry)} has no "id"`, fix: 'give the entry an "id": the pack name' });
126	      continue;
127	    }
128	    for (const key of Object.keys(entry)) {
129	      if (!PACK_ENTRY_KEYS.includes(key)) {
130	        errors.push({ what: `unknown property "${key}" on the "${entry.id}" pack entry`, fix: `remove it or fix the name — valid entry properties: ${PACK_ENTRY_KEYS.join(', ')}` });
131	      }
132	    }
133	    const badShape = (prop, expected) =>
134	      errors.push({ what: `"${prop}" on the "${entry.id}" pack entry must be ${expected}`, fix: `fix or remove the entry's "${prop}"` });
135	    const normalized = { id: packEntryId(entry) };
136	    if (entry.config !== undefined) {
137	      if (entry.config !== null && typeof entry.config === 'object' && !Array.isArray(entry.config)) normalized.config = entry.config;
138	      else badShape('config', 'an object of the pack\'s parameters');
139	    }
140	    if (entry.answers !== undefined) {
141	      if (entry.answers !== null && typeof entry.answers === 'object' && !Array.isArray(entry.answers)
142	        && Object.values(entry.answers).every((v) => typeof v === 'string')) normalized.answers = entry.answers;
143	      else badShape('answers', 'an object mapping the pack\'s question ids to string answers');
144	    }
145	    if (entry.rules !== undefined) {
146	      if (entry.rules !== null && typeof entry.rules === 'object' && !Array.isArray(entry.rules)) normalized.rules = entry.rules;
147	      else badShape('rules', 'an object of per-rule severity overrides');
148	    }
149	    if (entry.accept !== undefined) {
150	      if (Array.isArray(entry.accept)) normalized.accept = entry.accept;
151	      else badShape('accept', 'an array of acceptance entries');
152	    }
153	    if (entry.via !== undefined) {
154	      // Written by the declaration resolver on materialized dependencies
155	      // (engine/pack_loader/pack-registry.mjs) — normalized through so readers (the adoption
156	      // interview) can tell a chosen pack from a pulled-in one.
157	      if (Array.isArray(entry.via) && entry.via.every((v) => typeof v === 'string')) normalized.via = entry.via;
158	      else badShape('via', 'an array of pack ids (the declaration resolver writes it)');
159	    }
160	    packs.push(normalized.id);
161	    packEntries.push(normalized);
162	  }
163	
164	  // --- rules: top-level and per-entry merged; a conflict is a settings error,
165	  // never a silent last-writer-wins — two packs (or a pack and the top level)
166	  // disagreeing about a rule's severity is a decision the project must make.
167	  const rules = {};
168	  const ruleSource = {};
169	  const mergeRules = (overrides, source) => {
170	    for (const [ruleId, severity] of Object.entries(overrides)) {
171	      if (ruleId in rules && rules[ruleId] !== severity) {
172	        errors.push({
173	          what: `rule "${ruleId}" is set to "${rules[ruleId]}" by ${ruleSource[ruleId]} and "${severity}" by ${source}`,
174	          fix: 'make the overrides agree, or keep the rule on one of them',
175	        });
176	        continue;
177	      }
178	      rules[ruleId] = severity;
179	      ruleSource[ruleId] = source;
180	    }
181	  };
182	  if (raw.rules && typeof raw.rules === 'object') mergeRules(raw.rules, 'the top-level "rules"');
183	  for (const entry of packEntries) {
184	    if (entry.rules) mergeRules(entry.rules, `the "${entry.id}" pack entry`);
185	  }
186	
187	  // --- accept: top-level entries, then each pack entry's stamped with its
188	  // provenance (`pack: <id>` — which declaration motivated the exemption).
189	  const accept = Array.isArray(raw.accept) ? [...raw.accept] : [];
190	  for (const entry of packEntries) {
191	    for (const a of entry.accept ?? []) accept.push({ ...a, pack: entry.id });
192	  }
193	
194	  // --- packConfig view: per-pack parameters — e.g. the dirs a repo's
195	  // package.json lives in for the node pack's env install. Entry `config` is
196	  // the home; the legacy top-level key stays readable underneath it.
197	  const packConfig = raw.packConfig && typeof raw.packConfig === 'object' && !Array.isArray(raw.packConfig) ? { ...raw.packConfig } : {};
198	  for (const entry of packEntries) {
199	    if (entry.config !== undefined) packConfig[entry.id] = entry.config;
200	  }
201	
202	  return {
203	    packs,
204	    packEntries,
205	    rules,
206	    accept,
207	    sharedConstants: Array.isArray(raw.sharedConstants) ? raw.sharedConstants : [],
208	    packConfig,
209	    errors,
210	  };
211	}
212	
213	export function buildContext({ root, mode = 'changed', baseOverride = null, transcriptPath = null }) {
214	  root = resolve(root);
215	  const baseRef = baseOverride || resolveBaseRef(root);
216	  const mergeBase = baseRef ? (gitTry(root, 'merge-base', 'HEAD', baseRef) || '').trim() || null : null;
217	  // Diffing against HEAD keeps uncommitted work in scope even when no base branch resolves.
218	  const diffBase = mergeBase || 'HEAD';
219	
220	  const tracked = lines(gitTry(root, 'ls-files'));
221	  const untracked = lines(gitTry(root, 'ls-files', '--others', '--exclude-standard'));
222	
223	  const vsBase = lines(gitTry(root, 'diff', '--name-only', '--diff-filter=d', diffBase));
224	  let scanned;
225	  if (mode === 'all') {
226	    scanned = [...tracked, ...untracked];
227	  } else {
228	    scanned = [...new Set([...vsBase, ...untracked])];
229	  }
230	  // The vendored corpus under the shared mount is canon-owned, never the
231	  // project's own code — structurally out of scope for every check, on any git
232	  // host and any checkout (deliberately not attribute-driven). The consumer's
233	  // own .claudinite/local_packs/ sits BESIDE the shared mount and stays fully
234	  // in scope.
235	  // git emits '/'-separated paths on every platform; SHARED_SUBDIR is joined
236	  // with the platform separator, so normalize before prefix-matching.
237	  const sharedPrefix = `${SHARED_SUBDIR.split(sep).join('/')}/`;
238	  scanned = scanned.filter((f) => !f.startsWith(sharedPrefix));
239	  // Every in-scope regular file, vendored/generated included.
240	  const allFiles = scanned.filter((f) => existsSync(join(root, f)) && statSync(join(root, f)).isFile());
241	  // The default sweep excludes vendored/generated files, so `ctx.files` is the
242	  // project's OWN authored code and every check skips them for free (see vendoredSet).
243	  const vendored = vendoredSet(root, allFiles);
244	  const files = allFiles.filter((f) => !vendored.has(f));
245	  // The in-scope files the current change touched (vs the scoping base),
246	  // untracked included — the file set behind lines.mjs addedLines, for
247	  // check-the-work rules that judge the work rather than re-audit the world.
248	  const changedSet = new Set([...vsBase, ...untracked]);
249	  const changedFiles = files.filter((f) => changedSet.has(f));
250	
251	  const deleted = mergeBase ? lines(gitTry(root, 'diff', '--name-only', '--diff-filter=D', mergeBase)) : [];
252	
253	  let commits = [];
254	  if (mergeBase) {
255	    const out = gitTry(root, 'log', '--format=%s%n%b%x00', `${mergeBase}..HEAD`);
256	    commits = (out || '').split('\0').map((m) => m.trim()).filter(Boolean);
257	  }
258	
259	  const branch = (gitTry(root, 'rev-parse', '--abbrev-ref', 'HEAD') || '').trim();
260	
261	  // Conversation surface: the Stop hook forwards the session's transcript_path;
262	  // every other surface (CI, a manual run) has none, and conversation rules must
263	  // return [] when this is null. Parsed lazily and cached — most sweeps never ask.
264	  let conversationCache;
265	
266	  return {
267	    root,
268	    mode,
269	    baseRef,
270	    mergeBase,
271	    files,
