import { finding } from '../../../../engine/checks/helpers/findings.mjs';
import { matchingLines } from '../../../../engine/checks/helpers/line-scanning.mjs';

// A Google ID token carries an email claim regardless of verification; it is
// trustworthy only together with email_verified. Two static signatures in
// handler code: (a) reading the email claim in a file that never mentions
// email_verified; (b) comparing email_verified to a boolean with strict
// equality behind an API Gateway JWT authorizer, which stringifies claims — the
// claim arrives as the string 'true', so a strict boolean compare silently
// rejects every genuinely-verified user. Repo-state on purpose: both are live
// auth defects however long ago they merged.
//
// RELEVANCE FIRST (see engine/checks/README.md "Adding a rule"): a skill check runs on
// EVERY repo, and email_verified is standard OIDC, so two gates keep this
// Google-scoped: per file, only non-test code files handling verified-token
// claims (an authorizer context or a verify call); per repo, only when some
// file carries a Google identity marker (the accounts issuer or a
// googleusercontent client id) — evaluated lazily, once a candidate finding
// exists. The skill's own directory is excluded so its fixtures never
// self-flag on the corpus repo.
const SELF = 'skills/google-id-token-validation/';
const CODE_EXT = /\.(mjs|cjs|jsx?|tsx?|py)$/;
const TESTISH = /(^|\/)(tests?|__tests__|spec)\/|\.(test|spec)\./;
const CLAIMS_CONTEXT = /requestContext\s*\.\s*authorizer|jwt\.claims|verifyIdToken|jwtVerify/;
const EMAIL_ACCESS = /\b(claims|payload)\??\.email\b(?!_)|(claims|payload)\[['"]email['"]\]/;
const STRICT_BOOL = /email_verified\W{0,4}\s*[!=]==\s*(true|false)\b/;
const GOOGLE_MARKER = /accounts\.google\.com|\.apps\.googleusercontent\.com/;

const rule = {
  id: 'google-token-email-verified',
  severity: 'blocking',
  description: 'Handler code trusts a Google ID token\'s email claim only when email_verified says so, compared as the authorizer delivers it',
  doc: 'skills/google-id-token-validation/SKILL.md',
  why: 'a Google ID token carries email regardless of verification — an action gated on the bare claim trusts an address Google has not verified; and behind an API Gateway JWT authorizer the claim arrives as a string, so a strict boolean compare silently rejects every genuinely-verified user',

  run(ctx) {
    const handlers = ctx.files.filter((f) =>
      !f.startsWith(SELF) && CODE_EXT.test(f) && !TESTISH.test(f) && CLAIMS_CONTEXT.test(ctx.read(f) ?? ''));
    const candidates = [
      ...matchingLines(ctx, handlers.filter((f) => !/email_verified/.test(ctx.read(f) ?? '')), EMAIL_ACCESS)
        .map(({ file, line }) => finding(rule, {
          file, line,
          what: 'reads the token\'s email claim but never checks email_verified',
          fix: 'gate any identity-bearing action on the email_verified claim being true (behind an API Gateway JWT authorizer it arrives as the string \'true\')',
        })),
      ...matchingLines(ctx, handlers.filter((f) => /requestContext/.test(ctx.read(f) ?? '')), STRICT_BOOL)
        .map(({ file, line }) => finding(rule, {
          file, line,
          what: 'compares email_verified to a boolean with strict equality behind an API Gateway authorizer',
          fix: 'compare against the string \'true\' (or coerce) — the authorizer stringifies claims, so a strict boolean compare rejects every verified user',
        })),
    ];
    if (candidates.length === 0) return [];
    const googleRepo = ctx.files.some((f) => !f.startsWith(SELF) && GOOGLE_MARKER.test(ctx.read(f) ?? ''));
    return googleRepo ? candidates : [];
  },
};

export default rule;
import { finding } from '../../../../engine/checks/helpers/findings.mjs';
import { matchingLines } from '../../../../engine/checks/helpers/line-scanning.mjs';

// A Google ID token is accepted on three things: signature, issuer, audience.
// Every Google-issued token shares the one issuer, so a validator whose
// expected audience is unset accepts tokens minted for ANY Google OAuth client
// — an authentication bypass that looks completely valid. Repo-state on
// purpose: a pre-existing unset audience is a live bypass and must keep firing
// until fixed, however long ago it merged.
//
// RELEVANCE FIRST (see engine/checks/README.md "Adding a rule"): a skill check runs on
// EVERY repo, so the gate is narrow — only config-format files (yaml/json/toml/
// tf) that use the word "issuer" and carry the bare Google issuer origin
// (scheme + host with no path; a path form is a client-side OAuth URL, not an
// issuer). Code-form verifiers (jose, jsonwebtoken) have no reliable
// file-scoped signature and are not scanned. The skill's own directory is
// excluded so its fixtures never self-flag on the corpus repo.
const SELF = 'skills/google-id-token-validation/';
const CONFIG_EXT = /\.(ya?ml|json|toml|tf)$/;
const BARE_ISSUER = /https:\/\/accounts\.google\.com(?![\w/.-])/;
const ISSUER_WORD = /issuer/i;
const AUD_MENTION = /\baud(ience)?\b/i;
const EMPTY_AUD = /aud(ience)?["']?\s*[:=]\s*(\[\s*\]|""|'')/i;

const rule = {
  id: 'google-token-audience-pinned',
  severity: 'blocking',
  description: 'A validator config declaring the Google accounts issuer pins a non-empty expected audience',
  doc: 'skills/google-id-token-validation/SKILL.md',
  why: 'every Google-issued ID token shares that issuer, so signature + issuer alone accept a token minted for any Google OAuth client — the audience claim is the only thing that scopes a token to this app, and an unset audience is a full authentication bypass',

  run(ctx) {
    const configs = ctx.files.filter((f) => !f.startsWith(SELF) && CONFIG_EXT.test(f));
    return matchingLines(ctx, configs, BARE_ISSUER)
      .filter(({ file }) => {
        const text = ctx.read(file) ?? '';
        return ISSUER_WORD.test(text) && !(AUD_MENTION.test(text) && !EMPTY_AUD.test(text));
      })
      .map(({ file, line }) => finding(rule, {
        file, line,
        what: 'declares the Google accounts issuer with no (or an explicitly empty) expected audience',
        fix: 'configure the validator\'s audience to your exact OAuth web-application client id, next to the issuer; never leave it unset',
      }));
  },
};

export default rule;
import { finding } from '../../../../engine/checks/helpers/findings.mjs';
import { matchingLines } from '../../../../engine/checks/helpers/line-scanning.mjs';

// Chrome ships speech recognition only under the webkit-prefixed constructor;
// other Chromium contexts (headless, non-Chromium browsers, the test binding)
// expose neither. Constructing `new webkitSpeechRecognition()` directly — with
// no feature-detect of the unprefixed `SpeechRecognition` name — throws a bare
// ReferenceError wherever the prefixed global is absent, taking down the whole
// module instead of degrading to a no-op. The portable form resolves the
// constructor once (`globalThis.SpeechRecognition ?? globalThis.webkitSpeechRecognition`)
// and gates an `available` flag on it existing.
//
// RELEVANCE FIRST (see engine/checks/README.md "Adding a rule"): a skill check runs on
// EVERY repo, so the gate is the anti-pattern itself — a source file that
// directly constructs the prefixed recognizer AND never mentions the unprefixed
// `SpeechRecognition` name (its presence anywhere, in a `??`/`||` fallback or a
// feature test, means the file is aware of both and is not scanned — a
// conservative gate that would rather miss than false-flag). Advisory: a lone
// direct construction is a smell to judge, not proof of a break. The skill's own
// directory is excluded so its fixtures never self-flag on the corpus repo.
const SELF = 'skills/web-speech-io/';
const SOURCE = /\.(mjs|cjs|jsx?|tsx?)$/;
const DIRECT_PREFIXED = /new\s+webkitSpeechRecognition\s*\(/;

// The unprefixed identifier, NOT the webkit-prefixed one — a stripped copy of
// the text (prefixed occurrences removed) makes the word-boundary test exact.
function featureDetects(text) {
  return /\bSpeechRecognition/.test(text.replace(/webkitSpeechRecognition/g, ''));
}

const rule = {
  id: 'web-speech-recognition-feature-detected',
  severity: 'advisory',
  description: 'Speech recognition is obtained through a feature-detect, not by constructing the webkit-prefixed API directly',
  doc: 'skills/web-speech-io/SKILL.md',
  why: 'Chrome exposes recognition only under the webkit prefix and headless/non-Chromium contexts expose neither, so `new webkitSpeechRecognition()` with no unprefixed fallback throws a bare ReferenceError wherever the prefixed global is absent instead of degrading to a no-op',

  run(ctx) {
    const files = ctx.files.filter((f) =>
      !f.startsWith(SELF) && SOURCE.test(f) && !featureDetects(ctx.read(f) ?? ''));
    return matchingLines(ctx, files, DIRECT_PREFIXED).map(({ file, line }) => finding(rule, {
      file, line,
      what: 'constructs the webkit-prefixed recognizer directly with no unprefixed SpeechRecognition fallback',
      fix: 'resolve the constructor once via `globalThis.SpeechRecognition ?? globalThis.webkitSpeechRecognition` and gate an availability flag on it existing, so absent-API contexts degrade to a no-op',
    }));
  },
};

export default rule;

