+const PATH_CHAR = /[\w./@-]/;
+
+function widenToken(text, start, end) {
+  let s = start;
+  let e = end;
+  while (s > 0 && PATH_CHAR.test(text[s - 1])) s--;
+  while (e < text.length && PATH_CHAR.test(text[e])) e++;
+  return text.slice(s, e);
