60	if (has('--init')) {
61	  const path = join(root, '.claudinite-checks.json');
62	  if (existsSync(path)) {
63	    console.log(`${path} already exists — leaving it as-is.`);
64	    process.exit(0);
65	  }
66	  const ctx = buildContext({ root, mode: 'all' });
67	  // No pack is active by default, so the baseline is seeded as an explicit
68	  // declaration alongside the fingerprinted packs: every pack that flags
69	  // `seededByDefault` is written in (discovered structurally — the engine names
70	  // no pack), plus the ones a fingerprint detects. A seeded pack is still
71	  // opt-out-able where its own policy allows (baselining re-adds only the packs
72	  // whose absence it treats as drift), so removing a seeded declaration can
73	  // stick; each seeded pack ships its own one-time seed migration for the fleet.
74	  // Local packs are declared by hand, never fingerprinted or seeded — exclude
75	  // them from --init's seeding so a repo that already carries local packs (but
76	  // no config yet) doesn't auto-declare them.
77	  const seeded = packs.filter((p) => p.seededByDefault && !p.local).map((p) => p.id);
78	  const detected = [...seeded, ...packs.filter((p) => p.detect && !p.local && p.detect(ctx)).map((p) => p.id)];
79	  // A pack can't be imported without its dependencies — pull each declared pack's
80	  // `requires` closure into the declaration so it's complete and visible.
81	  const declared = resolveDeclaredPacks(detected, packs);
82	  // maintenance.delivery is deliberately materialized, not defaulted — the selection
