29	  ];
30	  for (const r of rules.sort((a, b) => a.id.localeCompare(b.id))) {
31	    console.log(`${r.id}\t${r.severity}\t${r.description}\t${r.doc}`);
32	  }
33	  process.exit(0);
34	}
35	
36	if (has('--init')) {
37	  const path = join(root, '.claudinite-checks.json');
38	  if (existsSync(path)) {
39	    console.log(`${path} already exists — leaving it as-is.`);
40	    process.exit(0);
41	  }
42	  const { packs } = await discoverPacks({ localRoot: root });
43	  const ctx = buildContext({ root, mode: 'all' });
44	  // No pack is active by default, so the baseline is seeded as an explicit
45	  // declaration alongside the fingerprinted packs: every pack that flags
46	  // `seededByDefault` is written in (discovered structurally — the engine names
47	  // no pack), plus the ones a fingerprint detects. A seeded pack is still
