30	// checks.mjs is gathered onto `skillChecks` and run by the runner only when the
31	// pack is active.
32	async function scanPackDir(dir, { local }, errors) {
33	  const out = [];
34	  if (!existsSync(dir)) return out;
35	  // A non-directory (or unreadable path) at a scan root is a fault to REPORT, not
36	  // a crash — the whole point of discovery being fail-soft is a diagnostic instead
37	  // of a dead runner (the SessionStart hooks fail soft; the runner surfaces it).
38	  let names;
39	  try {
40	    names = readdirSync(dir, { withFileTypes: true })
41	      .filter((d) => d.isDirectory()).map((d) => d.name).sort();
42	  } catch (e) {
43	    errors.push({
44	      what: `${local ? LOCAL_PACKS_SUBDIR : 'packs/'} is not a readable directory: ${e.message}`,
45	      fix: `make ${local ? LOCAL_PACKS_SUBDIR : 'packs/'} a directory (or remove it)`,
46	      dir,
47	    });
48	    return out;
49	  }
50	  for (const name of names) {
51	    const packDir = join(dir, name);
52	    const rel = local ? `${LOCAL_PACKS_SUBDIR}/${name}` : `packs/${name}`;
53	    const manifest = join(packDir, 'pack.mjs');
54	    if (!existsSync(manifest)) continue;
55	    let mod;
56	    try {
57	      mod = (await import(pathToFileURL(manifest).href)).default;
58	    } catch (e) {
59	      errors.push({
60	        what: `the pack in ${rel} failed to load: ${e.message}`,
61	        fix: `fix pack.mjs in ${rel}, or remove the pack`,
62	        dir: packDir,
63	      });
64	      continue;
65	    }
66	    if (!mod || typeof mod.id !== 'string') {
67	      errors.push({
68	        what: `the pack in ${rel} has no string "id" default export`,
69	        fix: 'export default { id: "<name>", ... } from its pack.mjs',
70	        dir: packDir,
71	      });
72	      continue;
73	    }
74	    // A local pack's id must equal its directory name. The engine activates a pack
